script:
frappe.ui.form.on("Purchase Order", {
    supplier(frm){
        if (!frm.doc.tax_category){
            set_tax_category(frm);   
        }
    },
    custom_company_gst_state_no: function (frm) {
        if (!frm.doc.tax_category){
            set_tax_category(frm);   
        }
    },
    custom_supplier_gst_state_no: function (frm) {
        if(frm.doc.docstatus == 0){
            if (!frm.doc.tax_category){
                set_tax_category(frm);   
            }
        }
    },
    refresh: function (frm) {
        if (frm.doc.custom_company_gst_state_no && frm.doc.custom_supplier_gst_state_no && frm.doc.docstatus == 0) {
            set_tax_category(frm);
        }
    },
    cost_center: function (frm) {
        if (frm.doc.items) {
            frm.doc.items.forEach(function (row) {
                row.cost_center = frm.doc.cost_center;
            });
            frm.refresh_field('items');
        }
    }
});

function set_tax_category(frm) {
    if (!frm.doc.gst_category) return;

    if (frm.doc.gst_category === "Unregistered") {
        frm.set_value("tax_category", "Intra-State Supply");
    } 
    else if (frm.doc.gst_category === "Registered Regular") {
        if (frm.doc.custom_company_gst_state_no === frm.doc.custom_supplier_gst_state_no) {
            frm.set_value("tax_category", "Intra-State Supply");
        } else {
            frm.set_value("tax_category", "Inter-State Supply");
        }
    }

    frm.refresh_field("tax_category");
}

frappe.ui.form.on("Sales Order", {
    customer(frm){
        set_tax_category(frm);
    },
    customer_address(frm){
        if (!frm.doc.tax_category){
            set_tax_category(frm);   
        }
    },
    refresh(frm){
        if(frm.doc.docstatus == 0){
            if (!frm.doc.tax_category){
                set_tax_category(frm);   
            }
        }
    }
});

function set_tax_category(frm) {
    if (!frm.doc.gst_category) return;

    if (frm.doc.gst_category === "Unregistered") {
        frm.set_value("tax_category", "Intra-State Supply");
    } 
    else if (frm.doc.gst_category === "Registered Regular") {
        if (frm.doc.custom_customer_gst_state_no === frm.doc.custom_company_gst_state_no) {
            frm.set_value("tax_category", "Intra-State Supply");
        } else {
            frm.set_value("tax_category", "Inter-State Supply");
        }
    }
    frm.refresh_field("tax_category");
}

frappe.ui.form.on('Customer', {
    setup(frm) {
        frm.set_query("account_manager", function () {
            return {
                query: "frappe.core.doctype.user.user.user_query",
                filters: {
                    role: "Accounts Manager"
                }
            };
        });
    }
});
